import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos, guardarProducto } from '../services/productoService';

const Inventario = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [editandoId, setEditandoId] = useState(null); // Nuevo: rastrea si estamos editando
    const [nuevoProd, setNuevoProd] = useState({
        codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas'
    });

    useEffect(() => {
        const sesionActiva = localStorage.getItem('usuarioLogueado');
        if (!sesionActiva) {
            alert("⚠️ Acceso denegado. Por favor, inicia sesión.");
            navigate("/"); 
        } else {
            cargarProductos();
        }
    }, [navigate]);

    const cargarProductos = async () => {
        const data = await obtenerProductos();
        setProductos(data);
    };

    // Nuevo: Función para cargar los datos en el formulario para editar
    const prepararEdicion = (p) => {
        setEditandoId(p.id);
        setNuevoProd({
            codigo: p.codigo,
            nombre: p.nombre,
            stock: p.stock,
            precioCompra: p.precioCompra,
            precioVenta: p.precioVenta,
            categoria: p.categoria
        });
    };

    const handleGuardar = async (e) => {
        e.preventDefault();
        const matriculaAutor = localStorage.getItem('usuarioLogueado') || 'desconocido';
        
        const productoData = { 
            ...nuevoProd, 
            id: editandoId, // Si es null, el backend crea uno nuevo; si tiene ID, lo actualiza
            registradoPorMatricula: matriculaAutor 
        };
        
        await guardarProducto(productoData);
        alert(editandoId ? "✅ Producto actualizado" : "✅ Producto guardado");
        
        // Limpiar formulario y estados
        setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });
        setEditandoId(null);
        cargarProductos();
    };

    const handleLogout = () => {
        localStorage.removeItem('usuarioLogueado');
        navigate("/");
    };

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <h2>📦 Inventario - Isla Tecnológica</h2>
                <button onClick={handleLogout} style={{ backgroundColor: '#dc3545', color: 'white', padding: '8px 15px', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
                    Cerrar Sesión
                </button>
            </div>
            
            <form onSubmit={handleGuardar} style={{ marginBottom: '30px', border: '1px solid #ccc', padding: '15px', borderRadius: '8px', backgroundColor: editandoId ? '#fff3cd' : '#f8f9fa' }}>
                <h3>{editandoId ? "✏️ Editando Producto" : "➕ Agregar Nuevo Producto"}</h3>
                <input placeholder="Código" value={nuevoProd.codigo} onChange={e => setNuevoProd({...nuevoProd, codigo: e.target.value})} required style={{ margin: '5px', padding: '5px' }} />
                <input placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} required style={{ margin: '5px', padding: '5px' }} />
                <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: parseInt(e.target.value)})} required style={{ margin: '5px', padding: '5px' }} />
                <input type="number" step="0.01" placeholder="Precio Compra" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({...nuevoProd, precioCompra: parseFloat(e.target.value)})} required style={{ margin: '5px', padding: '5px' }} />
                <input type="number" step="0.01" placeholder="Precio Venta" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({...nuevoProd, precioVenta: parseFloat(e.target.value)})} required style={{ margin: '5px', padding: '5px' }} />
                
                <button type="submit" style={{ backgroundColor: editandoId ? '#ffc107' : '#28a745', color: 'black', cursor: 'pointer', padding: '8px 20px', border: 'none', borderRadius: '5px', fontWeight: 'bold' }}>
                    {editandoId ? "Actualizar Producto" : "Guardar Producto"}
                </button>
                
                {editandoId && (
                    <button type="button" onClick={() => {setEditandoId(null); setNuevoProd({codigo:'', nombre:'', stock:0, precioCompra:0, precioVenta:0, categoria:'Fundas'})}} style={{ marginLeft: '10px', padding: '8px', cursor: 'pointer' }}>
                        Cancelar
                    </button>
                )}
            </form>

            <table border="1" width="100%" style={{ textAlign: 'left', borderCollapse: 'collapse' }}>
                <thead style={{ backgroundColor: '#f4f4f4' }}>
                    <tr>
                        <th>Código</th>
                        <th>Nombre</th>
                        <th>Stock</th>
                        <th>Costo ($)</th>
                        <th>Venta ($)</th>
                        <th>Ganancia ($)</th>
                        <th>Acciones</th> {/* Nueva columna */}
                    </tr>
                </thead>
                <tbody>
                    {productos.map(p => (
                        <tr key={p.id}>
                            <td style={{ padding: '10px' }}>{p.codigo}</td>
                            <td>{p.nombre}</td>
                            <td style={{ color: p.stock < 5 ? 'red' : 'black', fontWeight: p.stock < 5 ? 'bold' : 'normal' }}>{p.stock}</td>
                            <td>{p.precioCompra}</td>
                            <td>{p.precioVenta}</td>
                            <td style={{ fontWeight: 'bold', color: 'green' }}>{(p.precioVenta - p.precioCompra).toFixed(2)}</td>
                            <td>
                                <button onClick={() => prepararEdicion(p)} style={{ backgroundColor: '#007bff', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '3px', cursor: 'pointer' }}>
                                    Editar
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Inventario;
